20080	    uint32_t gate_up_count[DS4_MAX_LAYER][DS4_MAX_EXPERT];
20081	    uint32_t down_count[DS4_MAX_LAYER][DS4_MAX_EXPERT];
20082	    float *ffn_norm_buf;
20083	    float *routed_mid_buf;
20084	    uint16_t *routed_mid_f16_buf;
20085	    int   *selected_buf;
20086	    float *sq_tmp;
20087	    uint32_t cap_tokens;
20088	    uint64_t observed_tokens;
20089	    uint64_t observed_routes;
20090	    uint32_t chunks;
20091	    const char *dataset_path;
20092	} ds4_imatrix_collector;
20093	
20094	static bool imatrix_collector_init(ds4_imatrix_collector *c, uint32_t cap_tokens, const char *dataset_path) {
20095	    memset(c, 0, sizeof(*c));
20096	    c->cap_tokens = cap_tokens ? cap_tokens : 1u;
20097	    c->dataset_path = dataset_path;
20098	    const size_t gate_n = (size_t)DS4_N_LAYER * DS4_N_EXPERT * DS4_N_EMBD;
20099	    const size_t down_n = (size_t)DS4_N_LAYER * DS4_N_EXPERT * DS4_N_FF_EXP;
20100	    c->gate_up_sum2 = xcalloc(gate_n, sizeof(c->gate_up_sum2[0]));
20101	    c->down_sum2 = xcalloc(down_n, sizeof(c->down_sum2[0]));
20102	    c->ffn_norm_buf = xmalloc((size_t)c->cap_tokens * DS4_N_EMBD * sizeof(c->ffn_norm_buf[0]));
20103	    c->routed_mid_buf = xmalloc((size_t)c->cap_tokens * DS4_N_EXPERT_USED * DS4_N_FF_EXP * sizeof(c->routed_mid_buf[0]));
20104	    c->routed_mid_f16_buf = xmalloc((size_t)c->cap_tokens * DS4_N_EXPERT_USED * DS4_N_FF_EXP * sizeof(c->routed_mid_f16_buf[0]));
20105	    c->selected_buf = xmalloc((size_t)c->cap_tokens * DS4_N_EXPERT_USED * sizeof(c->selected_buf[0]));
20106	    c->sq_tmp = xmalloc((size_t)DS4_N_EMBD * sizeof(c->sq_tmp[0]));
20107	    return c->gate_up_sum2 && c->down_sum2 && c->ffn_norm_buf &&
20108	           c->routed_mid_buf && c->routed_mid_f16_buf && c->selected_buf && c->sq_tmp;
20109	}
