20112	    if (!c) return;
20113	    free(c->gate_up_sum2);
20114	    free(c->down_sum2);
20115	    free(c->ffn_norm_buf);
20116	    free(c->routed_mid_buf);
20117	    free(c->routed_mid_f16_buf);
