20125	}
20126	
20127	static float *imatrix_down_ptr(ds4_imatrix_collector *c, uint32_t il, uint32_t expert) {
20128	    return c->down_sum2 + ((size_t)il * DS4_N_EXPERT + expert) * DS4_N_FF_EXP;
20129	}
20130	
20131	static bool imatrix_collect_layer_batch(
20132	        ds4_imatrix_collector *c,
20133	        ds4_gpu_graph         *g,
20134	        uint32_t               il,
20135	        uint32_t               n_tokens) {
20136	    if (!c || n_tokens == 0) return true;
20137	    if (n_tokens > c->cap_tokens) return false;
20138	
20139	    const uint64_t norm_bytes = (uint64_t)n_tokens * DS4_N_EMBD * sizeof(float);
20140	    const uint64_t mid_elems = (uint64_t)n_tokens * DS4_N_EXPERT_USED * DS4_N_FF_EXP;
20141	    const uint64_t mid_bytes = mid_elems * (g->batch_routed_mid_is_f16 ? sizeof(uint16_t) : sizeof(float));
20142	    const uint64_t sel_bytes = (uint64_t)n_tokens * DS4_N_EXPERT_USED * sizeof(int);
20143	    void *mid_dst = g->batch_routed_mid_is_f16
20144	        ? (void *)c->routed_mid_f16_buf
20145	        : (void *)c->routed_mid_buf;
20146	    if (ds4_gpu_tensor_read(g->batch_ffn_norm, 0, c->ffn_norm_buf, norm_bytes) == 0 ||
20147	        ds4_gpu_tensor_read(g->batch_routed_mid, 0, mid_dst, mid_bytes) == 0 ||
20148	        ds4_gpu_tensor_read(g->batch_router_selected, 0, c->selected_buf, sel_bytes) == 0)
20149	    {
20150	        return false;
20151	    }
20152	
20153	    for (uint32_t t = 0; t < n_tokens; t++) {
20154	        const float *x = c->ffn_norm_buf + (size_t)t * DS4_N_EMBD;
20155	        for (uint32_t i = 0; i < DS4_N_EMBD; i++) c->sq_tmp[i] = x[i] * x[i];
20156	
20157	        for (uint32_t slot = 0; slot < DS4_N_EXPERT_USED; slot++) {
20158	            const int expert = c->selected_buf[(size_t)t * DS4_N_EXPERT_USED + slot];
20159	            if (expert < 0 || (uint32_t)expert >= DS4_N_EXPERT) continue;
20160	
20161	            float *gate_up = imatrix_gate_up_ptr(c, il, (uint32_t)expert);
20162	            for (uint32_t i = 0; i < DS4_N_EMBD; i++) gate_up[i] += c->sq_tmp[i];
20163	            c->gate_up_count[il][expert]++;
20164	
20165	            float *down = imatrix_down_ptr(c, il, (uint32_t)expert);
20166	            const size_t mid_off = ((size_t)t * DS4_N_EXPERT_USED + slot) * DS4_N_FF_EXP;
20167	            if (g->batch_routed_mid_is_f16) {
20168	                const uint16_t *mid = c->routed_mid_f16_buf + mid_off;
20169	                for (uint32_t i = 0; i < DS4_N_FF_EXP; i++) {
20170	                    const float v = f16_to_f32(mid[i]);
20171	                    down[i] += v * v;
20172	                }
20173	            } else {
20174	                const float *mid = c->routed_mid_buf + mid_off;
20175	                for (uint32_t i = 0; i < DS4_N_FF_EXP; i++) down[i] += mid[i] * mid[i];
20176	            }
20177	            c->down_count[il][expert]++;
20178	            c->observed_routes++;
20179	        }
20180	    }
20181	    c->observed_tokens += n_tokens;
20182	    c->chunks++;
20183	    return true;
20184	}
